// Prepare Wix collection data fields
const payload = $json.article;
const clientName = $json.clientName;
const telegramChatId = $json.telegramChatId;

return [{
  json: {
    clientName,
    telegramChatId,
    keyword: payload.primaryKeyword,
    title: payload.title,
    wixItemPayload: {
      title: payload.title,
      excerpt: payload.excerpt,
      richTextContent: `<p>${payload.bodyMarkdown.split('\n').join('</p><p>')}</p>`,
      status: "DRAFT"
    }
  }
}];

// Stub for Wix API request. In production, replace this node with Wix Data API HTTP Request node.
return [{
  json: {
    id: "mock-wix-post-id-12345",
    message: "Wix API request simulated"
  }
}];

const res = $('Mock Wix Post Request').first().json;
const schema = $('Schema Wix').first().json;
const triggerData = $('Execute Workflow Trigger').first().json;

// Wix Dashboard Editor URL
const draftEditUrl = `https://manage.wix.com/dashboard/site-id-placeholder/blog/posts`;

return [{
  json: {
    clientName: schema.clientName,
    telegramChatId: schema.telegramChatId,
    draftEditUrl,
    keyword: schema.keyword,
    title: schema.title,
    article: triggerData.article || null,
    status: "success"
  }
}];
